const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const sumItemBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const quotePremium = (items: Item[]): number => {
  const itemsBase = sumItemBasePremiums(items);
  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(itemsBase + firstInsuranceSurcharge + PROCESSING_FEE);
};
